    correctAnswer:
      "Implemente las operaciones high_prio_lock, low_prio_lock y prio_unlock.\n\nSolución:\n\n```c\ntypedef {\npthread_mutex_t m;\npthread_cond_t c;\nint waiting_high_prio;\nint locked;\n} prio_mutex;\n\nvoid high_prio_lock(prio_mutex *m) {\npthread_mutex_lock(6m-&gt;m);\nwhile (m-&gt;locked) {\nm-&gt;waiting_high_prio++;\npthread_cond_wait(6m-&gt;c, 6m-&gt;m);\nm-&gt;waiting_high_prio--;\n}\nm-&gt;locked = 1;\npthread_mutex_unlock(6m-&gt;m);\n}\n\nvoid low_prio_lock(prio_mutex *m) {\npthread_mutex_lock(6m-&gt;m);\nwhile (m-&gt;locked || m-&gt;waiting_high_prio &gt; 0)\npthread_cond_wait(6m-&gt;c, 6m-&gt;m);\n\nm-&gt;locked = 1;\npthread_mutex_unlock(6m-&gt;m);\n}\n\nvoid prio_unlock(prio_mutex *m) {\npthread_mutex_lock(6m-&gt;m);\nm-&gt;locked = 0;\npthread_cond_broadcast(6m-&gt;c);\npthread_mutex_unlock(6m-&gt;m);\n}",
